const Ic = ({ n, size=18, color }) => (
  <svg width={size} height={size} viewBox="0 0 24 24" fill={color||"currentColor"} style={{display:"block",flexShrink:0}}>
    <path d={PATHS[n]||""} />
  </svg>
);

// ─── SHARED UI ────────────────────────────────────────────────────────────────
const Badge = ({ status }) => {
  const M = {
    "boş":["#dcfce7","#16a34a"],"məşğul":["#fee2e2","#dc2626"],"rezerv":["#fef9c3","#ca8a04"],
    "işlək":["#dcfce7","#16a34a"],"sıradan çıxıb":["#fee2e2","#dc2626"],"xidmətdə":["#fef9c3","#ca8a04"],
    "təsdiqlənib":["#dcfce7","#16a34a"],"gözlənilir":["#fef9c3","#ca8a04"],"rədd edilib":["#fee2e2","#dc2626"],
  };
  const [bg,col] = M[status]||["#f3f4f6","#6b7280"];
  return <span style={{background:bg,color:col,padding:"3px 10px",borderRadius:20,fontSize:12,fontWeight:600,whiteSpace:"nowrap"}}>{status.charAt(0).toUpperCase()+status.slice(1)}</span>;
};

const Bar = ({ v }) => {
  const c = v>=80?"#16a34a":v>=50?"#ca8a04":"#dc2626";
  return <div style={{background:"#f3f4f6",borderRadius:8,height:8,overflow:"hidden"}}><div style={{width:`${v}%`,background:c,height:"100%",borderRadius:8,transition:"width .5s"}} /></div>;
};

const Modal = ({ title, onClose, children, w=480 }) => (
  <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.55)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:300,padding:16}}>
    <div style={{background:"white",borderRadius:16,padding:32,width:w,maxWidth:"95vw",boxShadow:"0 24px 64px rgba(0,0,0,0.25)",maxHeight:"90vh",overflowY:"auto"}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:22}}>
        <h3 style={{margin:0,fontSize:17,fontWeight:700,color:"#0f2246"}}>{title}</h3>
        <button onClick={onClose} style={{background:"#f3f4f6",border:"none",borderRadius:7,width:30,height:30,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",color:"#6b7280"}}><Ic n="close" size={15} /></button>
      </div>
      {children}
    </div>
  </div>
);

const Fld = ({ label, children }) => (
  <div style={{marginBottom:14}}>
    <label style={{display:"block",fontSize:13,fontWeight:600,color:"#374151",marginBottom:5}}>{label}</label>
    {children}
  </div>
);

const baseInp = {width:"100%",padding:"10px 12px",border:"1.5px solid #e5e7eb",borderRadius:8,fontSize:13,outline:"none",boxSizing:"border-box",fontFamily:"inherit"};
const Inp  = (p) => <input  {...p} style={{...baseInp,...p.style}} />;
const Sel  = ({children,...p}) => <select  {...p} style={{...baseInp,background:"white",...p.style}}>{children}</select>;
const Txa  = (p) => <textarea {...p} style={{...baseInp,resize:"vertical",...p.style}} />;

const BtnRow = ({children}) => <div style={{display:"flex",gap:10,marginTop:22}}>{children}</div>;
const Btn = ({ v="primary", children, ...p }) => {
  const S = {
    primary:  {background:"#1a3a7c",color:"white",  border:"none"},
    secondary:{background:"white",  color:"#374151",border:"1.5px solid #e5e7eb"},
    danger:   {background:"#dc2626",color:"white",  border:"none"},
    success:  {background:"#16a34a",color:"white",  border:"none"},
    teal:     {background:"#0891b2",color:"white",  border:"none"},
  };
  return <button {...p} style={{flex:1,padding:"11px 14px",borderRadius:8,cursor:"pointer",fontWeight:600,fontSize:13,...S[v],...p.style}}>{children}</button>;
};

const StatCard = ({ label, value, sub, icon, color }) => (
  <div style={{background:"white",borderRadius:12,padding:"20px 22px",boxShadow:"0 2px 8px rgba(0,0,0,0.06)",display:"flex",alignItems:"center",gap:16}}>
    <div style={{width:46,height:46,borderRadius:12,background:color+"18",color,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}><Ic n={icon} size={22} /></div>
    <div>
      <div style={{fontSize:26,fontWeight:800,color:"#0f2246",lineHeight:1}}>{value}</div>
      <div style={{fontSize:13,color:"#64748b",marginTop:4}}>{label}</div>
      {sub && <div style={{fontSize:11,color,marginTop:2,fontWeight:600}}>{sub}</div>}
    </div>
  </div>
);

// ─── LOGIN ────────────────────────────────────────────────────────────────────
function Login({ onLogin }) {
  const [un,setUn]     = useState("");
  const [pw,setPw]     = useState("");
  const [show,setShow] = useState(false);
  const [err,setErr]   = useState("");
  const [busy,setBusy] = useState(false);

  const go = () => {
    if (!un||!pw) return;
    setErr(""); setBusy(true);
    setTimeout(() => {
      const u = CREDENTIALS.find(c => c.username===un.trim() && c.password===pw);
      if (u) onLogin(u);
      else { setErr("İstifadəçi adı və ya şifrə yanlışdır."); setBusy(false); }
    }, 500);
  };

  return (
    <div style={{minHeight:"100vh",  width:"100vw",display:"flex",alignItems:"center",justifyContent:"center",position:"relative",fontFamily:"'Segoe UI',system-ui,sans-serif"}}>
      <div style={{position:"absolute",inset:0,backgroundImage:`url(${AZTU_IMG})`,backgroundSize:"cover",backgroundRepeat:"no-repeat", backgroundAttachment:"fixed", backgroundPosition:"center",backgroundRepeat: "no-repeat", backgroundAttachment: "fixed",width: "100%",height: "100%",filter:"brightness(0.7)"}} />
      <div style={{position:"absolute",inset:0,background:"linear-gradient(150deg,rgba(8,20,55,0.55),rgba(14,40,90,0.25))"}} />
      <div style={{position:"relative",zIndex:1,width:420,background:"rgba(255,255,255,0.97)",borderRadius:20,padding:40,boxShadow:"0 32px 80px rgba(0,0,0,0.5)"}}>
        <div style={{textAlign:"center",marginBottom:30}}>
          <div style={{width:62,height:62,background:"#0f2246",borderRadius:15,display:"inline-flex",alignItems:"center",justifyContent:"center",marginBottom:14}}>
            <Ic n="building" size={30} color="white" />
          </div>
          <h1 style={{margin:0,fontSize:21,fontWeight:800,color:"#0f2246",letterSpacing:"-.02em"}}>AzTU RMS</h1>
          <p style={{margin:"6px 0 0",color:"#64748b",fontSize:13,lineHeight:1.6}}>Azərbaycan Texniki Universiteti<br/>Resurs İdarəetmə Sistemi</p>
        </div>

        <Fld label="İstifadəçi adı (@aztu.edu.az)">
          <div style={{position:"relative"}}>
            <span style={{position:"absolute",left:11,top:"50%",transform:"translateY(-50%)",color:"#94a3b8",pointerEvents:"none"}}><Ic n="person" size={16} /></span>
            <Inp value={un} onChange={e=>setUn(e.target.value)} onKeyDown={e=>e.key==="Enter"&&go()} placeholder="İstifadəçi adını daxil edin" style={{paddingLeft:36}} />
          </div>
        </Fld>

        <Fld label="Şifrə">
          <div style={{position:"relative"}}>
            <span style={{position:"absolute",left:11,top:"50%",transform:"translateY(-50%)",color:"#94a3b8",pointerEvents:"none"}}><Ic n="lock" size={16} /></span>
            <Inp type={show?"text":"password"} value={pw} onChange={e=>setPw(e.target.value)} onKeyDown={e=>e.key==="Enter"&&go()} placeholder="Şifrənizi daxil edin" style={{paddingLeft:36,paddingRight:40}} />
            <button onClick={()=>setShow(s=>!s)} style={{position:"absolute",right:10,top:"50%",transform:"translateY(-50%)",background:"none",border:"none",cursor:"pointer",color:"#94a3b8",display:"flex",padding:0}}>
              <Ic n={show?"eyeoff":"eye"} size={16} />
            </button>
          </div>
        </Fld>

        {err && (
          <div style={{background:"#fee2e2",color:"#dc2626",borderRadius:8,padding:"9px 13px",fontSize:13,marginBottom:14,display:"flex",alignItems:"center",gap:7}}>
            <Ic n="warning" size={14} />{err}
          </div>
        )}

        <button onClick={go} disabled={busy||!un||!pw} style={{width:"100%",padding:13,marginTop:4,background:(!un||!pw)?"#cbd5e1":"#1a3a7c",color:"white",border:"none",borderRadius:10,fontWeight:700,fontSize:15,cursor:(!un||!pw)?"not-allowed":"pointer",transition:"background .2s"}}>
          {busy?"Yüklənir...":"Daxil ol →"}
        </button>
      </div>
    </div>
  );
}

// ─── DASHBOARD ────────────────────────────────────────────────────────────────
function Dashboard({ rooms, equipment, reservations, user }) {
  const bos     = rooms.filter(r=>r.status==="boş").length;
  const ishlek  = equipment.filter(e=>e.status==="işlək").length;
  const pending = reservations.filter(r=>r.status==="gözlənilir");
  const critical= equipment.filter(e=>e.cond<50);
  return (
    <div>
      <div style={{marginBottom:26}}>
        <h2 style={{margin:0,fontSize:21,fontWeight:800,color:"#0f2246"}}>Xoş gəldiniz, {user.name.split(" ")[0]}!</h2>
        <p style={{margin:"4px 0 0",color:"#64748b",fontSize:13}}>AzTU Resurs İdarəetmə Sistemi — ümumi baxış</p>
      </div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:14,marginBottom:24}}>
        <StatCard label="Otaq / Lab"         value={rooms.length}     sub={`${bos} boş`}         icon="rooms"     color="#1a3a7c"/>
        <StatCard label="Avadanlıq"           value={equipment.length} sub={`${ishlek} işlək`}    icon="equipment" color="#0891b2"/>
        <StatCard label="Gözləyən rezerv"    value={pending.length}   sub="təsdiq gözləyir"      icon="calendar"  color="#ca8a04"/>
        <StatCard label="Kritik avadanlıq"   value={critical.length}  sub="texniki hal aşağı"    icon="warning"   color="#dc2626"/>
      </div>
      <div style={{display:"grid",gridTemplateColumns:"2fr 1fr",gap:18}}>
        <div style={{background:"white",borderRadius:12,padding:22,boxShadow:"0 2px 8px rgba(0,0,0,0.06)"}}>
          <h3 style={{margin:"0 0 16px",fontSize:14,fontWeight:700,color:"#0f2246"}}>Son rezervasiyalar</h3>
          {reservations.slice(0,5).map(r=>(
            <div key={r.id} style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"11px 0",borderBottom:"1px solid #f1f5f9"}}>
              <div>
                <div style={{fontWeight:600,fontSize:13,color:"#1e293b"}}>Otaq {r.room}</div>
                <div style={{fontSize:12,color:"#64748b"}}>{r.user} · {r.date} · {r.t1}–{r.t2}</div>
                <div style={{fontSize:11,color:"#94a3b8"}}>{r.purpose}</div>
              </div>
              <Badge status={r.status}/>
            </div>
          ))}
        </div>
        <div style={{background:"white",borderRadius:12,padding:22,boxShadow:"0 2px 8px rgba(0,0,0,0.06)"}}>
          <h3 style={{margin:"0 0 16px",fontSize:14,fontWeight:700,color:"#0f2246"}}>Otaq vəziyyəti</h3>
          {[["boş","#16a34a"],["məşğul","#dc2626"],["rezerv","#ca8a04"]].map(([s,c])=>{
            const n=rooms.filter(r=>r.status===s).length,pct=Math.round((n/rooms.length)*100);
            return (<div key={s} style={{marginBottom:14}}>
              <div style={{display:"flex",justifyContent:"space-between",marginBottom:5}}>
                <span style={{fontSize:13,color:"#374151",fontWeight:500}}>{s.charAt(0).toUpperCase()+s.slice(1)}</span>
                <span style={{fontSize:13,fontWeight:700,color:c}}>{n} ({pct}%)</span>
              </div>
              <Bar v={pct}/>
            </div>);
          })}
          {critical.length>0&&(
            <div style={{marginTop:18,paddingTop:14,borderTop:"1px solid #f1f5f9"}}>
              <div style={{fontSize:12,fontWeight:700,color:"#dc2626",marginBottom:8}}>⚠ Kritik avadanlıqlar</div>
              {critical.map(e=><div key={e.id} style={{fontSize:12,color:"#dc2626",marginBottom:3}}>• {e.name} ({e.cond}%)</div>)}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

// ─── ROOMS ────────────────────────────────────────────────────────────────────
function Rooms({ rooms, user, setPage, setPreRoom }) {
  const [srch,setSrch]   = useState("");
  const [fType,setFType] = useState("Hamısı");
  const [fStat,setFStat] = useState("Hamısı");
  const types = ["Hamısı",...new Set(rooms.map(r=>r.type))];
  const list  = rooms.filter(r=>{
    const mt=fType==="Hamısı"||r.type===fType;
    const ms=fStat==="Hamısı"||r.status===fStat;
    const mq=r.name.toLowerCase().includes(srch.toLowerCase())||r.type.toLowerCase().includes(srch.toLowerCase());
    return mt&&ms&&mq;
  });
  const doReserve = (name)=>{ setPreRoom(name); setPage("reservations"); };
  return (
    <div>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:22}}>
        <div>
          <h2 style={{margin:0,fontSize:20,fontWeight:800,color:"#0f2246"}}>Otaqlar və Laboratoriyalar</h2>
          <p style={{margin:"4px 0 0",color:"#64748b",fontSize:13}}>{rooms.length} otaq · {rooms.filter(r=>r.status==="boş").length} boş</p>
        </div>
      </div>
      <div style={{display:"flex",gap:10,marginBottom:18,flexWrap:"wrap"}}>
        <div style={{position:"relative",flex:"1 1 200px"}}>
          <span style={{position:"absolute",left:11,top:"50%",transform:"translateY(-50%)",color:"#94a3b8"}}><Ic n="search" size={15}/></span>
          <Inp value={srch} onChange={e=>setSrch(e.target.value)} placeholder="Axtar..." style={{paddingLeft:34}}/>
        </div>
        <Sel value={fType} onChange={e=>setFType(e.target.value)} style={{width:"auto"}}>{types.map(t=><option key={t}>{t}</option>)}</Sel>
        <Sel value={fStat} onChange={e=>setFStat(e.target.value)} style={{width:"auto"}}>
          {["Hamısı","boş","məşğul","rezerv"].map(s=><option key={s}>{s}</option>)}
        </Sel>
      </div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(270px,1fr))",gap:14}}>
        {list.map(r=>(
          <div key={r.id} style={{background:"white",borderRadius:12,padding:18,boxShadow:"0 2px 8px rgba(0,0,0,0.06)",border:r.status==="boş"?"1.5px solid #dcfce7":"1.5px solid #f1f5f9"}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:12}}>
              <div>
                <div style={{fontSize:17,fontWeight:800,color:"#0f2246"}}>Otaq {r.name}</div>
                <div style={{fontSize:12,color:"#64748b"}}>{r.type} · {r.floor}. mərtəbə</div>
              </div>
              <Badge status={r.status}/>
            </div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:12}}>
              <div style={{background:"#f8fafc",borderRadius:7,padding:"8px 10px"}}>
                <div style={{fontSize:11,color:"#94a3b8"}}>Tutum</div>
                <div style={{fontSize:14,fontWeight:700,color:"#1e293b"}}>{r.capacity} nəfər</div>
              </div>
              <div style={{background:"#f8fafc",borderRadius:7,padding:"8px 10px"}}>
                <div style={{fontSize:11,color:"#94a3b8"}}>Sahə</div>
                <div style={{fontSize:14,fontWeight:700,color:"#1e293b"}}>{r.area} m²</div>
              </div>
            </div>
            <div style={{marginBottom:12}}>
              <div style={{fontSize:11,color:"#94a3b8",marginBottom:5}}>Avadanlıqlar</div>
              <div style={{display:"flex",flexWrap:"wrap",gap:4}}>
                {r.equip.map(e=><span key={e} style={{fontSize:11,background:"#f0f4ff",color:"#1a3a7c",padding:"2px 7px",borderRadius:20,fontWeight:500}}>{e}</span>)}
              </div>
            </div>
            {r.status==="boş"&&(
              <button onClick={()=>doReserve(r.name)} style={{width:"100%",padding:"9px",background:"#1a3a7c",color:"white",border:"none",borderRadius:8,fontWeight:600,fontSize:13,cursor:"pointer"}}>
                Rezerv et
              </button>
            )}
          </div>
        ))}
      </div>
    </div>
  );
}

// ─── EQUIPMENT ────────────────────────────────────────────────────────────────
// NOTE: EqFormFields is defined OUTSIDE Equipment to prevent re-mount on rerender
function EqFormFields({ form, setForm }) {
  const F = (k,v) => setForm(p=>({...p,[k]:v}));
  return (
    <>
      <Fld label="Ad">
        <Inp value={form.name} onChange={e=>F("name",e.target.value)} placeholder="Avadanlıq adı" autoFocus />
      </Fld>
      <Fld label="Növ">
        <Inp value={form.type} onChange={e=>F("type",e.target.value)} placeholder="Proyektor, Noutbuk..." />
      </Fld>
      <Fld label="Otaq">
        <Inp value={form.room} onChange={e=>F("room",e.target.value)} placeholder="101, Lab-1..." />
      </Fld>
      <Fld label="İstismar statusu">
        <Sel value={form.status} onChange={e=>F("status",e.target.value)}>
          {["işlək","xidmətdə","sıradan çıxıb"].map(s=><option key={s}>{s}</option>)}
        </Sel>
      </Fld>
      <Fld label={`Texniki hal: ${form.cond}%`}>
        <input type="range" min={0} max={100} value={form.cond} onChange={e=>F("cond",e.target.value)} style={{width:"100%",marginBottom:6}} />
        <Bar v={Number(form.cond)}/>
      </Fld>
    </>
  );
}

function Equipment({ equipment, setEquipment, user }) {
  const [srch,setSrch]       = useState("");
  const [showAdd,setShowAdd] = useState(false);
  const [editItem,setEdit]   = useState(null);
  const [delItem,setDel]     = useState(null);
  const blank = {name:"",type:"",room:"",status:"işlək",cond:80};
  const [form,setForm]       = useState(blank);

  const isAdmin = user.role==="admin";
  const isTech  = user.role==="texnik";

  // For technician: only show faulty/serviced equipment grouped by room
  const faultyEq = equipment.filter(e=>e.status==="sıradan çıxıb"||e.status==="xidmətdə");

  const list = equipment.filter(e=>
    e.name.toLowerCase().includes(srch.toLowerCase())||
    e.type.toLowerCase().includes(srch.toLowerCase())||
    e.room.toLowerCase().includes(srch.toLowerCase())
  );

  const saveAdd = () => {
    setEquipment(p=>[...p,{...form,id:Date.now(),lastSvc:new Date().toISOString().split("T")[0],nextSvc:"",qr:"QR-"+Math.random().toString(36).substr(2,6).toUpperCase(),cond:Number(form.cond)}]);
    setShowAdd(false); setForm(blank);
  };
  const saveEdit = () => {
    setEquipment(p=>p.map(e=>e.id===editItem.id?{...e,...form,cond:Number(form.cond)}:e));
    setEdit(null);
  };
  const doDel = () => { setEquipment(p=>p.filter(e=>e.id!==delItem.id)); setDel(null); };
  const openEdit = item => { setEdit(item); setForm({name:item.name,type:item.type,room:item.room,status:item.status,cond:item.cond}); };

  // ── Technician view: problem equipment by room
  if (isTech) {
    const byRoom = {};
    faultyEq.forEach(e=>{ if(!byRoom[e.room]) byRoom[e.room]=[]; byRoom[e.room].push(e); });
    return (
      <div>
        <div style={{marginBottom:22}}>
          <h2 style={{margin:0,fontSize:20,fontWeight:800,color:"#0f2246"}}>Nasaz / Xidmətdəki Avadanlıqlar</h2>
          <p style={{margin:"4px 0 0",color:"#64748b",fontSize:13}}>{faultyEq.length} avadanlıq diqqət tələb edir</p>
        </div>
        {faultyEq.length===0?(
          <div style={{background:"white",borderRadius:12,padding:32,textAlign:"center",color:"#16a34a",fontSize:15,fontWeight:600}}>
            ✓ Bütün avadanlıqlar işlək vəziyyətdədir.
          </div>
        ):(
          Object.entries(byRoom).map(([room,items])=>(
            <div key={room} style={{background:"white",borderRadius:12,padding:20,boxShadow:"0 2px 8px rgba(0,0,0,0.06)",marginBottom:14}}>
              <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:14,paddingBottom:12,borderBottom:"1px solid #f1f5f9"}}>
                <div style={{width:36,height:36,background:"#fff0f0",borderRadius:9,display:"flex",alignItems:"center",justifyContent:"center",color:"#dc2626"}}>
                  <Ic n="building" size={18}/>
                </div>
                <div>
                  <div style={{fontWeight:700,fontSize:15,color:"#0f2246"}}>Otaq {room}</div>
                  <div style={{fontSize:12,color:"#64748b"}}>{items.length} avadanlıq problemli</div>
                </div>
              </div>
              {items.map(e=>(
                <div key={e.id} style={{display:"flex",alignItems:"center",gap:14,padding:"10px 0",borderBottom:"1px solid #f8fafc"}}>
                  <div style={{flex:1}}>
                    <div style={{fontWeight:600,fontSize:13,color:"#1e293b"}}>{e.name}</div>
                    <div style={{fontSize:12,color:"#64748b"}}>{e.type} · QR: {e.qr}</div>
                    <div style={{fontSize:11,color:"#94a3b8"}}>Son xidmət: {e.lastSvc}</div>
                  </div>
                  <div style={{width:120}}>
                    <Bar v={e.cond}/>
                    <div style={{fontSize:11,color:e.cond<50?"#dc2626":"#ca8a04",fontWeight:600,marginTop:3}}>{e.cond}% · {e.cond<50?"Kritik":"Orta"}</div>
                  </div>
                  <Badge status={e.status}/>
                </div>
              ))}
            </div>
          ))
        )}
      </div>
    );
  }

  // ── Admin view
  return (
    <div>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:22}}>
        <div>
          <h2 style={{margin:0,fontSize:20,fontWeight:800,color:"#0f2246"}}>Avadanlıq İnventarı</h2>
          <p style={{margin:"4px 0 0",color:"#64748b",fontSize:13}}>{equipment.length} avadanlıq qeydiyyatda</p>
        </div>
        {isAdmin&&(
          <button onClick={()=>{setForm(blank);setShowAdd(true);}} style={{display:"flex",alignItems:"center",gap:7,padding:"10px 16px",background:"#1a3a7c",color:"white",border:"none",borderRadius:8,fontWeight:600,fontSize:13,cursor:"pointer"}}>
            <Ic n="plus" size={15}/> Yeni avadanlıq
          </button>
        )}
      </div>
      <div style={{position:"relative",marginBottom:16}}>
        <span style={{position:"absolute",left:11,top:"50%",transform:"translateY(-50%)",color:"#94a3b8"}}><Ic n="search" size={15}/></span>
        <Inp value={srch} onChange={e=>setSrch(e.target.value)} placeholder="Avadanlıq axtarın..." style={{paddingLeft:34}}/>
      </div>
      <div style={{background:"white",borderRadius:12,boxShadow:"0 2px 8px rgba(0,0,0,0.06)",overflowX:"auto"}}>
        <table style={{width:"100%",borderCollapse:"collapse",minWidth:700}}>
          <thead>
            <tr style={{background:"#f8fafc"}}>
              {["Ad","Növ","Otaq","QR","Status","Texniki hal","Hal",...(isAdmin?["Əməliyyat"]:[])].map(h=>(
                <th key={h} style={{padding:"11px 14px",textAlign:"left",fontSize:11,fontWeight:700,color:"#64748b",textTransform:"uppercase",letterSpacing:".05em",whiteSpace:"nowrap"}}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {list.map((e,i)=>(
              <tr key={e.id} style={{borderTop:"1px solid #f1f5f9",background:i%2===0?"white":"#fafafa"}}>
                <td style={{padding:"13px 14px",fontSize:13,fontWeight:600,color:"#1e293b"}}>{e.name}</td>
                <td style={{padding:"13px 14px",fontSize:13,color:"#64748b"}}>{e.type}</td>
                <td style={{padding:"13px 14px",fontSize:13,color:"#64748b"}}>{e.room}</td>
                <td style={{padding:"13px 14px"}}><span style={{display:"flex",alignItems:"center",gap:5,fontSize:11,color:"#1a3a7c",fontFamily:"monospace"}}><Ic n="qr" size={12}/>{e.qr}</span></td>
                <td style={{padding:"13px 14px"}}><Badge status={e.status}/></td>
                <td style={{padding:"13px 14px",minWidth:130}}>
                  <div style={{display:"flex",alignItems:"center",gap:8}}><Bar v={e.cond}/><span style={{fontSize:12,fontWeight:700,color:e.cond>=80?"#16a34a":e.cond>=50?"#ca8a04":"#dc2626",whiteSpace:"nowrap"}}>{e.cond}%</span></div>
                </td>
                <td style={{padding:"13px 14px"}}>
                  {e.cond<50&&<span style={{fontSize:11,color:"#dc2626",fontWeight:600}}>⚠ Kritik</span>}
                  {e.cond>=50&&e.cond<75&&<span style={{fontSize:11,color:"#ca8a04",fontWeight:600}}>Orta</span>}
                  {e.cond>=75&&<span style={{fontSize:11,color:"#16a34a",fontWeight:600}}>Yaxşı</span>}
                </td>
                {isAdmin&&(
                  <td style={{padding:"13px 14px"}}>
                    <div style={{display:"flex",gap:6}}>
                      <button onClick={()=>openEdit(e)} title="Redaktə et" style={{width:30,height:30,background:"#f0f4ff",border:"none",borderRadius:7,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",color:"#1a3a7c"}}><Ic n="edit" size={14}/></button>
                      <button onClick={()=>setDel(e)}   title="Sil"        style={{width:30,height:30,background:"#fff0f0",border:"none",borderRadius:7,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",color:"#dc2626"}}><Ic n="trash" size={14}/></button>
                    </div>
                  </td>
                )}
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {showAdd&&(
        <Modal title="Yeni avadanlıq əlavə et" onClose={()=>setShowAdd(false)}>
          <EqFormFields form={form} setForm={setForm}/>
          <BtnRow><Btn v="secondary" onClick={()=>setShowAdd(false)}>Ləğv et</Btn><Btn v="primary" onClick={saveAdd}>Əlavə et</Btn></BtnRow>
        </Modal>
      )}
      {editItem&&(
        <Modal title="Avadanlığı redaktə et" onClose={()=>setEdit(null)}>
          <EqFormFields form={form} setForm={setForm}/>
          <BtnRow><Btn v="secondary" onClick={()=>setEdit(null)}>Ləğv et</Btn><Btn v="primary" onClick={saveEdit}>Yadda saxla</Btn></BtnRow>
        </Modal>
      )}
      {delItem&&(
        <Modal title="Silmək istəyirsiniz?" onClose={()=>setDel(null)} w={400}>
          <p style={{margin:"0 0 4px",fontSize:14,color:"#374151"}}><strong>{delItem.name}</strong> silinəcək. Bu əməliyyat geri alına bilməz.</p>
          <BtnRow><Btn v="secondary" onClick={()=>setDel(null)}>Ləğv et</Btn><Btn v="danger" onClick={doDel}>Sil</Btn></BtnRow>
        </Modal>
      )}
    </div>
  );
}

// ─── RESERVATIONS ─────────────────────────────────────────────────────────────
function Reservations({ rooms, reservations, setReservations, user, preRoom, setPreRoom }) {
  const [showForm,setShowForm]   = useState(!!preRoom);
  const [rejTarget,setRejTarget] = useState(null);
  const [rejReason,setRejReason] = useState("");
  const blank = {room:preRoom||"",date:"2026-05-13",t1:"09:00",t2:"11:00",purpose:"",teacherName:""};
  const [form,setForm] = useState(blank);
  const F = (k,v) => setForm(p=>({...p,[k]:v}));
  const muellims = CREDENTIALS.filter(c=>c.role==="muellim");
  const visible  = user.role==="admin" ? reservations : reservations.filter(r=>r.uid===user.id);
  const approve  = id => setReservations(p=>p.map(r=>r.id===id?{...r,status:"təsdiqlənib"}:r));
  const confirmReject = () => {
    setReservations(p=>p.map(r=>r.id===rejTarget.id?{...r,status:"rədd edilib",reason:rejReason}:r));
    setRejTarget(null); setRejReason("");
  };
  const submit = () => {
    if(!form.room||!form.purpose) return;
    let tu = user;
    if(user.role==="admin"&&form.teacherName) tu=CREDENTIALS.find(c=>c.name===form.teacherName)||user;
    setReservations(p=>[...p,{id:Date.now(),room:form.room,uid:tu.id,user:tu.name,date:form.date,t1:form.t1,t2:form.t2,purpose:form.purpose,status:user.role==="admin"?"təsdiqlənib":"gözlənilir",reason:""}]);
    setShowForm(false); setPreRoom(null); setForm(blank);
  };
  const closeForm = () => { setShowForm(false); setPreRoom(null); };
  return (
    <div>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:22}}>
        <div>
          <h2 style={{margin:0,fontSize:20,fontWeight:800,color:"#0f2246"}}>Rezervasiya sistemi</h2>
          <p style={{margin:"4px 0 0",color:"#64748b",fontSize:13}}>
            {user.role==="admin"?`${visible.length} rezervasiya · ${visible.filter(r=>r.status==="gözlənilir").length} gözləyir`:"Sizin rezervasiyalarınız"}
          </p>
        </div>
        <button onClick={()=>{setForm(blank);setShowForm(true);}} style={{display:"flex",alignItems:"center",gap:7,padding:"10px 16px",background:"#1a3a7c",color:"white",border:"none",borderRadius:8,fontWeight:600,fontSize:13,cursor:"pointer"}}>
          <Ic n="plus" size={15}/> Yeni rezerv
        </button>
      </div>
      <div style={{display:"grid",gap:10}}>
        {visible.length===0&&<div style={{background:"white",borderRadius:12,padding:32,textAlign:"center",color:"#94a3b8",fontSize:14}}>Hələ rezervasiya yoxdur.</div>}
        {visible.map(r=>(
          <div key={r.id} style={{background:"white",borderRadius:12,padding:18,boxShadow:"0 2px 8px rgba(0,0,0,0.06)"}}>
            <div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between",gap:14,flexWrap:"wrap"}}>
              <div style={{display:"flex",alignItems:"center",gap:14}}>
                <div style={{width:44,height:44,background:"#f0f4ff",borderRadius:10,display:"flex",alignItems:"center",justifyContent:"center",color:"#1a3a7c",flexShrink:0}}><Ic n="calendar" size={20}/></div>
                <div>
                  <div style={{fontWeight:700,fontSize:14,color:"#0f2246"}}>Otaq {r.room}</div>
                  <div style={{fontSize:12,color:"#64748b"}}>{r.user} · {r.date} · {r.t1}–{r.t2}</div>
                  <div style={{fontSize:12,color:"#94a3b8"}}>{r.purpose}</div>
                  {r.status==="rədd edilib"&&r.reason&&(
                    <div style={{marginTop:6,display:"flex",alignItems:"flex-start",gap:6,background:"#fff0f0",borderRadius:7,padding:"6px 10px"}}>
                      <Ic n="info" size={13} color="#dc2626"/>
                      <span style={{fontSize:12,color:"#dc2626",fontWeight:500}}>İmtina səbəbi: {r.reason}</span>
                    </div>
                  )}
                </div>
              </div>
              <div style={{display:"flex",alignItems:"center",gap:8,flexShrink:0}}>
                <Badge status={r.status}/>
                {user.role==="admin"&&r.status==="gözlənilir"&&(
                  <div style={{display:"flex",gap:6}}>
                    <button onClick={()=>approve(r.id)} style={{display:"flex",alignItems:"center",gap:4,padding:"6px 11px",background:"#dcfce7",color:"#16a34a",border:"none",borderRadius:7,cursor:"pointer",fontSize:12,fontWeight:600}}><Ic n="check" size={13}/> Təsdiqlə</button>
                    <button onClick={()=>{setRejTarget(r);setRejReason("");}} style={{display:"flex",alignItems:"center",gap:4,padding:"6px 11px",background:"#fee2e2",color:"#dc2626",border:"none",borderRadius:7,cursor:"pointer",fontSize:12,fontWeight:600}}><Ic n="close" size={13}/> Rədd et</button>
                  </div>
                )}
              </div>
            </div>
          </div>
        ))}
      </div>
      {showForm&&(
        <Modal title="Yeni rezervasiya" onClose={closeForm}>
          {user.role==="admin"&&(
            <Fld label="Müəllim adına (kim üçün)">
              <Sel value={form.teacherName} onChange={e=>F("teacherName",e.target.value)}>
                <option value="">Admin özü üçün</option>
                {muellims.map(m=><option key={m.id} value={m.name}>{m.name} — {m.title}</option>)}
              </Sel>
            </Fld>
          )}
          <Fld label="Otaq">
            <Sel value={form.room} onChange={e=>F("room",e.target.value)}>
              <option value="">Seçin...</option>
              {rooms.filter(r=>r.status==="boş"||r.name===form.room).map(r=><option key={r.id} value={r.name}>Otaq {r.name} — {r.type}</option>)}
            </Sel>
          </Fld>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:10}}>
            <Fld label="Tarix"><Inp type="date" value={form.date} onChange={e=>F("date",e.target.value)}/></Fld>
            <Fld label="Başlanğıc"><Inp type="time" value={form.t1} onChange={e=>F("t1",e.target.value)}/></Fld>
            <Fld label="Bitmə"><Inp type="time" value={form.t2} onChange={e=>F("t2",e.target.value)}/></Fld>
          </div>
          <Fld label="Məqsəd"><Inp value={form.purpose} onChange={e=>F("purpose",e.target.value)} placeholder="Mühazirə, seminar, imtahan..."/></Fld>
          {user.role==="muellim"&&<div style={{background:"#f0f9ff",border:"1px solid #bae6fd",borderRadius:8,padding:"9px 13px",fontSize:12,color:"#0891b2",marginBottom:4}}>Rezervasiya tələbiniz administratora göndəriləcək.</div>}
          {user.role==="admin"&&<div style={{background:"#f0fdf4",border:"1px solid #bbf7d0",borderRadius:8,padding:"9px 13px",fontSize:12,color:"#16a34a",marginBottom:4}}>Admin rezervasiyaları avtomatik təsdiqlənir.</div>}
          <BtnRow><Btn v="secondary" onClick={closeForm}>Ləğv et</Btn><Btn v="primary" onClick={submit}>Göndər</Btn></BtnRow>
        </Modal>
      )}
      {rejTarget&&(
        <Modal title="Rezervasiyanı rədd et" onClose={()=>setRejTarget(null)} w={440}>
          <div style={{background:"#f8fafc",borderRadius:9,padding:"12px 14px",marginBottom:16,fontSize:13,color:"#374151"}}>
            <strong>Otaq {rejTarget.room}</strong> · {rejTarget.user}<br/>
            <span style={{color:"#64748b",fontSize:12}}>{rejTarget.date} · {rejTarget.t1}–{rejTarget.t2} · {rejTarget.purpose}</span>
          </div>
          <Fld label="İmtina səbəbi (müəllimə göstəriləcək)">
            <Txa rows={3} value={rejReason} onChange={e=>setRejReason(e.target.value)} placeholder="Məsələn: Həmin vaxt otaq artıq istifadədədir..."/>
          </Fld>
          <BtnRow>
            <Btn v="secondary" onClick={()=>setRejTarget(null)}>Ləğv et</Btn>
            <Btn v="danger" onClick={confirmReject} style={{flex:2}}><span style={{display:"flex",alignItems:"center",justifyContent:"center",gap:5}}><Ic n="close" size={14}/>Rədd et</span></Btn>
          </BtnRow>
        </Modal>
      )}
    </div>
  );
}

// ─── MONITORING ───────────────────────────────────────────────────────────────
function Monitoring({ rooms, equipment }) {
  const [tick,setTick]         = useState(0);
  const [sensorLog,setSensorLog] = useState([]);

  useEffect(()=>{
    const id = setInterval(()=>{
      setTick(t=>{
        const newTick = t+1;
        setSensorLog(prev=>{
          const snap = rooms.slice(0,6).map((r,i)=>({
            otaq:r.name,
            tip:r.type,
            temp:(19+(((Math.sin(i*7.3+newTick*0.4)*43758)%1+1)/2)*9).toFixed(1),
            rumbet:Math.round(35+(((Math.sin(i*1.9+newTick*0.4)*43758)%1+1)/2)*40),
            isiq:Math.round(150+(((Math.sin(i*2.7+newTick*0.4)*43758)%1+1)/2)*650),
            co2:Math.round(380+(((Math.sin(i*3.5+newTick*0.4)*43758)%1+1)/2)*440),
            vaxt:new Date().toLocaleTimeString("az-AZ"),
          }));
          return [...prev.slice(-50), ...snap];
        });
        return newTick;
      });
    }, 10000);
    // initial fire
    setSensorLog(rooms.slice(0,6).map((r,i)=>({
      otaq:r.name, tip:r.type,
      temp:(19+(((Math.sin(i*7.3)*43758)%1+1)/2)*9).toFixed(1),
      rumbet:Math.round(35+(((Math.sin(i*1.9)*43758)%1+1)/2)*40),
      isiq:Math.round(150+(((Math.sin(i*2.7)*43758)%1+1)/2)*650),
      co2:Math.round(380+(((Math.sin(i*3.5)*43758)%1+1)/2)*440),
      vaxt:new Date().toLocaleTimeString("az-AZ"),
    })));
    return ()=>clearInterval(id);
  },[]);

  const s = (i,t,a,b) => a+(((Math.sin(i*7.3+t*0.4)*43758)%1+1)/2)*(b-a);

  const sensors = rooms.slice(0,6).map((r,i)=>({
    room:r.name, type:r.type, status:r.status,
    temp:    s(i,  tick,19,28).toFixed(1),
    humidity:Math.round(s(i+1,tick,35,75)),
    light:   Math.round(s(i+2,tick,150,800)),
    co2:     Math.round(s(i+3,tick,380,820)),
  }));

  const exportExcel = () => {
    if(sensorLog.length===0) { alert("Hələ məlumat toplanmayıb. 10 saniyə gözləyin."); return; }
    const ws = XLSX.utils.json_to_sheet(sensorLog.map(r=>({
      "Otaq":r.otaq, "Tip":r.tip,
      "Temperatur (°C)":r.temp,
      "Rütubət (%)":r.rumbet,
      "İşıq (lx)":r.isiq,
      "CO₂ (ppm)":r.co2,
      "Vaxt":r.vaxt,
    })));
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Sensor Məlumatları");
    // equipment sheet
    const ws2 = XLSX.utils.json_to_sheet(equipment.map(e=>({
      "Ad":e.name,"Növ":e.type,"Otaq":e.room,
      "Status":e.status,"Texniki hal (%)":e.cond,
      "Son xidmət":e.lastSvc,"Növbəti xidmət":e.nextSvc,"QR":e.qr,
    })));
    XLSX.utils.book_append_sheet(wb, ws2, "Avadanlıq Vəziyyəti");
    XLSX.writeFile(wb, `AzTU_Monitoring_${new Date().toISOString().split("T")[0]}.xlsx`);
  };

  return (
    <div>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:22}}>
        <div>
          <h2 style={{margin:0,fontSize:20,fontWeight:800,color:"#0f2246"}}>Monitorinq Paneli</h2>
          <p style={{margin:"4px 0 0",color:"#64748b",fontSize:13}}>Real vaxt sensor məlumatları — hər 10 saniyədə yenilənir · {sensorLog.length} qeyd toplanıb</p>
        </div>
        <button onClick={exportExcel} style={{display:"flex",alignItems:"center",gap:8,padding:"10px 18px",background:"#059669",color:"white",border:"none",borderRadius:8,fontWeight:600,fontSize:13,cursor:"pointer"}}>
          <Ic n="download" size={16}/> Excel Export
        </button>
      </div>

      <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(290px,1fr))",gap:14,marginBottom:22}}>
        {sensors.map((s,i)=>(
          <div key={i} style={{background:"white",borderRadius:12,padding:18,boxShadow:"0 2px 8px rgba(0,0,0,0.06)"}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:14}}>
              <div>
                <div style={{fontWeight:700,fontSize:14,color:"#0f2246"}}>Otaq {s.room}</div>
                <div style={{fontSize:12,color:"#64748b"}}>{s.type}</div>
              </div>
              <span style={{fontSize:11,padding:"3px 9px",borderRadius:20,fontWeight:600,background:s.status==="məşğul"?"#fee2e2":"#f0fdf4",color:s.status==="məşğul"?"#dc2626":"#16a34a"}}>
                {s.status==="məşğul"?"● Məşğul":"● Boş"}
              </span>
            </div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8}}>
              {[
                {label:"🌡 Temperatur",val:`${s.temp}°C`,    al:s.temp>25    },
                {label:"💧 Rütubət",   val:`${s.humidity}%`, al:s.humidity>65},
                {label:"☀️ İşıq",      val:`${s.light} lx`,  al:s.light<300  },
                {label:"🌿 CO₂",       val:`${s.co2} ppm`,   al:s.co2>700    },
              ].map(m=>(
                <div key={m.label} style={{background:m.al?"#fff5f5":"#f8fafc",borderRadius:8,padding:"9px 11px",border:m.al?"1px solid #fecaca":"1px solid transparent"}}>
                  <div style={{fontSize:11,color:"#94a3b8"}}>{m.label}</div>
                  <div style={{fontSize:15,fontWeight:700,color:m.al?"#dc2626":"#1e293b"}}>{m.val}</div>
                  {m.al&&<div style={{fontSize:10,color:"#dc2626"}}>⚠ Normadan kənar</div>}
                </div>
              ))}
            </div>
          </div>
        ))}
      </div>

      <div style={{background:"white",borderRadius:12,padding:22,boxShadow:"0 2px 8px rgba(0,0,0,0.06)"}}>
        <h3 style={{margin:"0 0 16px",fontSize:14,fontWeight:700,color:"#0f2246"}}>Avadanlıq texniki vəziyyəti</h3>
        <div style={{display:"grid",gap:11}}>
          {equipment.map(e=>(
            <div key={e.id} style={{display:"flex",alignItems:"center",gap:12}}>
              <div style={{width:180,fontSize:13,color:"#374151",fontWeight:500,flexShrink:0,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}} title={e.name}>{e.name}</div>
              <div style={{flex:1}}><Bar v={e.cond}/></div>
              <div style={{width:42,textAlign:"right",fontSize:13,fontWeight:700,color:e.cond>=80?"#16a34a":e.cond>=50?"#ca8a04":"#dc2626"}}>{e.cond}%</div>
              <div style={{width:115}}><Badge status={e.status}/></div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

// ─── ROOT ─────────────────────────────────────────────────────────────────────
export default function App() {
  const [user,setUser]       = useState(null);
  const [page,setPage]       = useState(null);
  const [rooms]              = useState(INIT_ROOMS);
  const [equipment,setEq]    = useState(INIT_EQ);
  const [reservations,setRes]= useState(INIT_RES);
  const [preRoom,setPreRoom] = useState(null);

  const login  = u => { setUser(u); setPage(ACCESS[u.role][0]); };
  const logout = ()=> { setUser(null); setPage(null); };

  if(!user) return <Login onLogin={login}/>;
  const allowed = ACCESS[user.role];

  return (
    <div style={{display:"flex",minHeight:"100vh",background:"#f1f5f9",fontFamily:"'Segoe UI',system-ui,sans-serif"}}>
      <aside style={{width:236,background:"#0f2246",display:"flex",flexDirection:"column",flexShrink:0,position:"fixed",top:0,left:0,bottom:0,zIndex:50}}>
        <div style={{padding:"22px 18px",borderBottom:"1px solid rgba(255,255,255,0.08)"}}>
          <div style={{display:"flex",alignItems:"center",gap:11}}>
            <div style={{width:36,height:36,background:"rgba(255,255,255,0.12)",borderRadius:10,display:"flex",alignItems:"center",justifyContent:"center"}}><Ic n="building" size={20} color="white"/></div>
            <div>
              <div style={{color:"white",fontWeight:800,fontSize:15,lineHeight:1}}>AzTU RMS</div>
              <div style={{color:"rgba(255,255,255,0.4)",fontSize:10,marginTop:2}}>v2.1 · Demo</div>
            </div>
          </div>
        </div>
        <nav style={{flex:1,padding:"14px 10px"}}>
          {allowed.map(id=>(
            <button key={id} onClick={()=>setPage(id)} style={{width:"100%",display:"flex",alignItems:"center",gap:11,padding:"10px 12px",borderRadius:8,border:"none",background:page===id?"rgba(255,255,255,0.13)":"transparent",color:page===id?"white":"rgba(255,255,255,0.48)",cursor:"pointer",fontSize:13,fontWeight:page===id?700:500,marginBottom:2,textAlign:"left",transition:"all .15s"}}>
              <Ic n={PAGE_META[id].icon} size={17}/>{PAGE_META[id].label}
            </button>
          ))}
        </nav>
        <div style={{padding:"14px 18px",borderTop:"1px solid rgba(255,255,255,0.08)"}}>
          <div style={{marginBottom:8}}>
            <span style={{fontSize:10,padding:"3px 9px",borderRadius:20,background:ROLE_COLOR[user.role]+"55",color:"white",fontWeight:600}}>{ROLE_LABEL[user.role]}</span>
          </div>
          <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:11}}>
            <div style={{width:33,height:33,borderRadius:8,background:ROLE_COLOR[user.role],display:"flex",alignItems:"center",justifyContent:"center",color:"white",fontSize:13,fontWeight:700,flexShrink:0}}>{user.name[0]}</div>
            <div style={{overflow:"hidden"}}>
              <div style={{color:"white",fontSize:12,fontWeight:600,lineHeight:1,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{user.name}</div>
              <div style={{color:"rgba(255,255,255,0.38)",fontSize:11,marginTop:2}}>{user.title}</div>
            </div>
          </div>
          <button onClick={logout} style={{width:"100%",display:"flex",alignItems:"center",gap:7,padding:"7px 10px",background:"rgba(255,255,255,0.06)",border:"none",borderRadius:6,color:"rgba(255,255,255,0.45)",cursor:"pointer",fontSize:12}}>
            <Ic n="logout" size={13}/> Çıxış
          </button>
        </div>
      </aside>
      <main style={{marginLeft:236,flex:1,padding:30,minHeight:"100vh"}}>
        {page==="dashboard"    && <Dashboard    rooms={rooms} equipment={equipment} reservations={reservations} user={user}/>}
        {page==="rooms"        && <Rooms        rooms={rooms} user={user} setPage={setPage} setPreRoom={setPreRoom}/>}
        {page==="equipment"    && <Equipment    equipment={equipment} setEquipment={setEq} user={user}/>}
        {page==="reservations" && <Reservations rooms={rooms} reservations={reservations} setReservations={setRes} user={user} preRoom={preRoom} setPreRoom={setPreRoom}/>}
        {page==="monitoring"   && <Monitoring   rooms={rooms} equipment={equipment}/>}
      </main>
    </div>
  );
}
